#!/usr/bin/env node
/**
 * Generate responsive image variants for hero images.
 *
 * For each .webp in public/images/hero/, creates -640w, -1024w, and -1920w
 * variants that match the srcSet generated by responsiveSrc() from
 * @drzach/website-toolkit.
 *
 * Only creates variants that don't already exist (idempotent).
 *
 * Usage:  node scripts/generate-responsive-images.js
 */

import sharp from 'sharp';
import { readdir, stat } from 'node:fs/promises';
import { join, basename, extname } from 'node:path';

const HERO_DIR = join(import.meta.dirname, '..', 'public', 'images', 'hero');
const WIDTHS = [640, 1024, 1920];
const QUALITY = 80;

async function exists(path) {
  try {
    await stat(path);
    return true;
  } catch {
    return false;
  }
}

async function main() {
  const files = (await readdir(HERO_DIR)).filter(
    (f) => f.endsWith('.webp') && !/-\d+w\.webp$/.test(f)
  );

  console.log(`Found ${files.length} source images in ${HERO_DIR}`);

  let created = 0;
  let skipped = 0;

  for (const file of files) {
    const src = join(HERO_DIR, file);
    const ext = extname(file);
    const stem = basename(file, ext);

    for (const width of WIDTHS) {
      const outName = `${stem}-${width}w${ext}`;
      const outPath = join(HERO_DIR, outName);

      if (await exists(outPath)) {
        skipped++;
        continue;
      }

      await sharp(src)
        .resize({ width, withoutEnlargement: true })
        .webp({ quality: QUALITY })
        .toFile(outPath);

      created++;
      console.log(`  Created ${outName}`);
    }
  }

  console.log(`Done. Created ${created} variants, skipped ${skipped} existing.`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
